import React, { useState } from "react";
import "./styles.css";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import Layout from "./components/Layout";
import ChatboxButton from "./components/ChatboxButton";
import Dashboard from "./pages/Dashboard";
import ProgramAvatar from "./pages/ProgramAvatar";
import Challenges from "./pages/Challenges";
import GoalsProgress from "./pages/GoalsProgress";
import ActivityFoodLog from "./pages/ActivityFoodLog";
import Notifications from "./pages/Notifications";
import Chatbot from "./pages/Chatbot";

function App() {
  // ── Avatar state lives here so it persists across page navigation ──
  const [avatarSelections, setAvatarSelections] = useState({
    skin:       's1',
    hairStyle:  'hs1',
    hairColor:  'hc1',
    animalEars: 'ae1',
    armour:     'ar1',
    pets:       null,
  });
  const [avatarName, setAvatarName] = useState('');

  return (
    <BrowserRouter>
      <Layout>
        <Routes>
          <Route path="/" element={<Dashboard />} />
          <Route
            path="/program"
            element={
              <ProgramAvatar
                avatarSelections={avatarSelections}
                setAvatarSelections={setAvatarSelections}
                avatarName={avatarName}
                setAvatarName={setAvatarName}
              />
            }
          />
          <Route path="/challenges" element={<Challenges />} />
          <Route path="/goals" element={<GoalsProgress />} />
          <Route path="/activity-food" element={<ActivityFoodLog />} />
          <Route path="/notifications" element={<Notifications />} />
          <Route path="/chatbot" element={<Chatbot />} />
        </Routes>
        <ChatboxButton />
      </Layout>
    </BrowserRouter>
  );
}

export default App;
